<template>

  <div class="sign-in">
    <div class="form__card outer-pad">
      <header class="form__card-header">
        <div class="h1">Ingresa tu número de teléfono móvil</div>
      </header>
      <p class="form__card-description">Te enviaremos un código para confirmar tus datos y puedas ingresar a Prospery.</p>
      <form @submit.prevent="login()" action="submit" class="form__card-fields">
        <fieldset class="form__fieldset">
          <label for="" class="label--input">Teléfono móvil</label>
          <span class="phone__country-indicator">+57</span>
          <input maxlength="10" v-model="userPhone"
                 :class="{'form__card-fields--failed' : !isPhoneValid}"
                 type="number"
                 required
                 oninput="javascript: if (this.value.length > this.maxLength) this.value = this.value.slice(0, this.maxLength - 1);"
                 class="input__tel">
        </fieldset>
        <button class="button button--wide button--large"
        :class="{'button--disabled': this.isLoading}"
        :disabled="this.isLoading"
        >Inicia Sesión</button>
      </form>
      <footer class="form__card-footer">
        <p class="">Al momento de ingresar estás aceptando nuestros <a href="">términos y condiciones.</a></p>
      </footer>
    </div>
    <alert typeOfAlert="loginError" v-if="!this.isPhoneValid"></alert>
    <router-view v-slot="{ Component }">
      <transition name="fade" appear mode="out-in">
        <component :is="Component" />
      </transition>
    </router-view>
  </div>

</template>

<script>
// @ is an alias to /src
import Alert from '../Alert'
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'
import deleteText from '../../icons/textfields/deleteText'
import { mapActions, mapGetters } from 'vuex'

export default {
  name: 'SignIn',
  data () {
    return {
      userPhone: '',
      isPhoneValid: Boolean,
      isLoading: false
    }
  },
  computed: {
    ...mapGetters('auth', {
      getterLoginStatus: 'getLoginStatus',
      getterCodeGenerationStatus: 'getCodeGenerationStatus'
    })
  },
  methods: {
    ...mapActions('auth', {
      actionLogin: 'generateCode'
    }),
    async login () {
      this.isLoading = true
      const phone = this.userPhone
      await this.actionLogin({ mobile: phone })
      if (this.getterCodeGenerationStatus === 'success') {
        this.$router.push('code-verification')
        this.isLoading = false
      }

      if (this.getterCodeGenerationStatus === 'error') {
        this.isPhoneValid = false
        this.isLoading = false
      }
    }
  },
  components: {
    hidePassword,
    showPassword,
    deleteText,
    Alert
  }
}
</script>
