/* eslint-disable no-unused-vars */
/* eslint-disable quotes */
/* eslint-disable space-before-function-paren */
/* eslint-disable semi */
import humps from "humps";
import {
  generateCodeApi,
  verifyCodeApi,
  completeRegistration,
  sendUserId
} from "../../api/auth";

const state = () => ({
  registrationStatus: localStorage.getItem("registrationStatus") || "",
  codeGenerationStatus: "",
  codeVerificationStatus: "",
  AuthData: {
    accessToken: localStorage.getItem("accessToken") || "",
    expiry: localStorage.getItem("expiry") || "",
    tokenType: localStorage.getItem("tokenType") || "",
    uid: localStorage.getItem("uid") || "",
    client: localStorage.getItem("client") || ""
  },
  userId: localStorage.getItem("userId") || "",
  userData: null,
  loginStatus: "",
  completePersonalData: {
    personalData: "",
    status: "",
    errors: []
  },
  idPhotos: {
    idFront: "",
    idBack: ""
  }
});

const mutations = {
  setLoginStatus(state, value) {
    state.loginStatus = value;
  },
  setCodeGenerationStatus(state, value) {
    state.codeGenerationStatus = value;
  },
  setRegistrationStatus(state, value) {
    localStorage.setItem("registrationStatus", value);
    state.registrationStatus = value;
  },
  setPhotos(state, { idFront, idBack }) {
    state.idPhotos = { idFront, idBack }
  },
  setCodeVerificationStatus(state, value) {
    state.codeVerificationStatus = value;
  },
  saveAuthData(state, payload) {
    const { tokenType, expiry, uid, client, accessToken } = payload;
    localStorage.setItem("tokenType", tokenType);
    localStorage.setItem("accessToken", accessToken);
    localStorage.setItem("expiry", expiry);
    localStorage.setItem("uid", uid);
    localStorage.setItem("client", client);
    state.AuthData = payload;
  },
  setUserData(state, payload) {
    localStorage.setItem("userId", payload.id);
    state.userData = payload;
  },
  fillPersonalDataForm(state, payload) {
    state.completePersonalData.personalData = payload;
  },
  setCompletePersonalData(state, payload) {
    const response = {
      personalData: state.completePersonalData.personalData,
      status: payload.status,
      errors: payload.errors || []
    };
    state.completePersonalData = response;
  },
  setCompleteVerification(state, payload) {
    const response = {
      status: payload.status,
      errors: payload.errors || []
    };
    state.completeVerification = response;
  },
  removeAuthData(state) {
    localStorage.removeItem("tokenType");
    localStorage.removeItem("accessToken");
    localStorage.removeItem("expiry");
    localStorage.removeItem("uid");
    localStorage.removeItem("client");
    state.AuthData = {
      accessToken: "",
      expiry: "",
      tokenType: "",
      uid: "",
      client: ""
    };
  }
};

const actions = {
  async generateCode({ commit }, payload) {
    const response = await generateCodeApi({ payload }).catch(() => {
      commit("setCodeGenerationStatus", "error");
    });

    if (response && response.data) {
      commit("setCodeGenerationStatus", "success");
    }
  },
  async verifyCode({ commit }, payload) {
    const response = await verifyCodeApi({ payload })
      .catch(() => {
        commit("setCodeVerificationStatus", "error");
      });

    if (response && response.data) {
      const authData = {
        tokenType: "Bearer",
        expiry: response.headers.expiry,
        uid: response.headers.uid,
        client: response.headers.client,
        accessToken: response.headers["access-token"]
      };

      const res = response.data;
      commit("setCodeVerificationStatus", res.user.aasm_state);
      commit("saveAuthData", authData);
      commit("setRegistrationStatus", "in-progress");
      commit("setUserData", humps.camelizeKeys(res.user));
    }
  },
  savePersonalDataForm({ commit }, payload) {
    commit("fillPersonalDataForm", payload);
  },
  async completePersonalData({ commit }, payload) {
    const headers = {
      "access-token": localStorage.getItem("accessToken") || "",
      expiry: localStorage.getItem("expiry") || "",
      "token-type": localStorage.getItem("tokenType") || "",
      uid: localStorage.getItem("uid") || "",
      client: localStorage.getItem("client") || ""
    };

    const response = await completeRegistration({ payload, headers })
      .catch(err => {
        const fieldErrors =
          err.response?.data?.errors?.find(error => error?.full_messages) || null;
        if (fieldErrors) {
          commit("setCompletePersonalData", {
            status: "error",
            errors: fieldErrors.full_messages
          });
        } else {
          commit("setCompletePersonalData", {
            status: "error",
            errors: ["Error inesperado"]
          });
        }
      });

    if (response && response.data) {
      const authData = {
        tokenType: "Bearer",
        expiry: response.headers.expiry,
        uid: response.headers.uid,
        client: response.headers.client,
        accessToken: response.headers["access-token"]
      };
      commit("saveAuthData", authData);
      commit("setCompletePersonalData", { status: "success" });
      commit("setRegistrationStatus", "completed");
    }
  },
  async verificationCustomer({ commit, state }, payload) {
    const clientId = localStorage.getItem("userId") || ""
    const headers = {
      "access-token": localStorage.getItem("accessToken") || "",
      expiry: localStorage.getItem("expiry") || "",
      "token-type": localStorage.getItem("tokenType") || "",
      uid: localStorage.getItem("uid") || "",
      client: localStorage.getItem("client") || ""
    };

    const response = await sendUserId({ payload, clientId, headers })
      .catch(err => {
        console.log(err);
        const fieldErrors =
          err.response?.data?.errors?.find(error => error?.full_messages) ||
          null;
        if (fieldErrors) {
          commit("setCompleteVerification", {
            status: "error",
            errors: fieldErrors.full_messages
          });
        } else {
          commit("setCompleteVerification", {
            status: "error",
            errors: "Error inesperado"
          });
        }
      });

    if (response && response.data) {
      commit("setCompleteVerification", { status: "success" });
    }
  },
  logOut({ commit }, payload) {
    commit("removeAuthData");
  },
  savePhotos({ commit }, payload) {
    commit("setPhotos", payload)
  }
};

const getters = {
  getLoginStatus(state) {
    return state.loginStatus;
  },
  getCodeGenerationStatus(state) {
    return state.codeGenerationStatus;
  },
  getCodeVerificationStatus(state) {
    return state.codeVerificationStatus;
  },
  getCompletePersonalDataStatus(state) {
    return state.completePersonalData;
  },
  getPhotos(state) {
    return state.idPhotos
  }
};

export default {
  namespaced: true,
  state,
  getters,
  actions,
  mutations
};
