<template>
  <div>
    <dashboard-header buttonText="" title="Agregar referencia" previousTitle="Referencias personales"></dashboard-header>
    <div class="dashboard-card outer-pad outer-pad--small">
      <header class="dashboard-card__header dashboard-card__header--extra-space">
        <p>Actualiza tus datos personales para mantener tu perfil al día</p>
      </header>
      <section class="dashboard-card__content">
        <form @submit.prevent="createReferences()" class="account-form">
          <fieldset class="silc-grid">
            <div class="silc-grid__col silc-grid__col--6-800">
              <label for="" class="label--input">Nombres
              </label>
              <input
                type="text"
                name="fullName"
                v-model="name"
                placeholder=""
              >
            </div>
            <div class="silc-grid__col silc-grid__col--6-800 silc-grid--relative">
              <label for="" class="label--input">Número de teléfono
              </label>
              <span class="phone__country-indicator">+57</span>
              <input
                type="tel"
                class="input__tel"
                name="mobile_phone"
                v-model="mobile_phone"
                placeholder=""
              >
            </div>
            <div class="silc-grid__col silc-grid__col--6-800 silc-grid--relative">
              <label for="" class="label--input">Dirección
              </label>
              <input
                type="address"
                name="address"
                v-model="address"
                placeholder=""
              >
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <div class="select">
                <label for="" class="label--input">Tipo de relación</label>
                <select class="select-standard" v-model="relation_type">
                  <option value="" selected disabled hidden>Seleccione una opción</option>
                  <option value="1">Cónyugue</option>
                  <option value="2">Familiar</option>
                  <option value="3">Amigo</option>
                </select>
              </div>
            </div>
            <div class="silc-grid__col silc-grid__col--6-800 silc-grid--relative">
              <div class="inline-icon__wrapper inline-icon__wrapper--sticked">
                <label for="" class="label--input">Parentesco</label>
                <verified-icon class="extra-small-icon"></verified-icon>
              </div>
              <input
                type="text"
                name="identification-number"
                v-model="relationship"
                placeholder=""
              >
            </div>
            <div class="silc-grid__col silc-grid__col--6-800 silc-grid--justify-right silc-grid__col--last-row">
              <button class="button button--large account-form__button" type="submit">Agregar referencia</button>
            </div>
          </fieldset>
        </form>
      </section>
    </div>
  </div>
</template>

<script>
import DashboardHeader from '../../components/dashboard/DashboardHeader'
import { mapActions } from 'vuex'

export default {
  components: {
    DashboardHeader
  },
  data () {
    return {
      name: '',
      last_name: 'Perez',
      address: '',
      mobile_phone: '',
      relation_type: '',
      relationship: ''
    }
  },
  methods: {
    ...mapActions('references', {
      actionCreateReference: 'sentReference'
    }),
    async createReferences () {
      const reference = {
        name: this.name,
        last_name: this.last_name,
        address: this.address,
        mobile_phone: this.mobile_phone,
        relation_type: this.relation_type,
        relationship: this.relationship
      }
      await this.actionCreateReference({ reference })
    }
  }
}
</script>
