<template>
  <transition name="fade" mode="out-in" appear>
    <div class="code-verification">
      <div class="form__card outer-pad">
        <header class="form__card-header">
          <code-verification-icon></code-verification-icon>
          <button class="button close">X</button>
        </header>
        <div class="h1">Introduce el código de verificación</div>
        <p class="form__card-description">Introduce el código de 6 dígitos que hemos enviado al correo registrado para continuar.</p>
        <form @submit.prevent="checkCode()" action="submit" class="form__card-fields">
          <fieldset>
            <label for="" class="label--input">Código de verificación</label>
            <input  ref="codeField"
                    type="text"
                    v-model="userCode"
                    :class="{'form__card-fields--failed': showAlert}">
          </fieldset>
          <button class="button button--wide button--large"
          :class="{'button--disabled': this.isLoading}"
          :disabled="this.isLoading"
          >Verificar código</button>
        </form>
        <footer class="form__card-footer">
          <div class="form__card-timer">
            <p class="footer__timer" ref="timer">01:00</p>
            <p class="paragraph--dark">Código enviado</p>
          </div>
          <p class="paragraph--dark">¿No has recibido ningún código? <a v-on:click="reSendCode()">Enviar de nuevo</a></p>
        </footer>
      </div>
      <alert v-if="showAlert" typeOfAlert="code"></alert>
    </div>
  </transition>
</template>

<script>
// @ is an alias to /src
import codeVerificationIcon from '../../icons/codeVerificationIcon'
import Alert from '../Alert'
import { mapActions, mapGetters } from 'vuex'

export default {
  name: 'CodeVerification',
  data () {
    return {
      timer: 0,
      userCode: '',
      apiCode: '1234',
      isCodeValid: false,
      prevLink: '',
      showAlert: false,
      isLoading: false
    }
  },
  methods: {
    ...mapActions('auth', {
      actionVerifyCode: 'verifyCode'
    }),
    startTimer (duration, display) {
      let timer = 0
      let minutes = 0
      let seconds
      setInterval(function () {
        minutes = parseInt(timer / 60, 10)
        seconds = parseInt(timer % 60, 10)

        minutes = minutes < 10 ? '0' + minutes : minutes
        seconds = seconds < 10 ? '0' + seconds : seconds

        if (--timer < 0) {
          timer = duration
        }
        display.textContent = minutes + ':' + seconds
      }, 1000)
    },
    async checkCode () {
      this.isLoading = true
      const code = this.userCode
      await this.actionVerifyCode({ code })

      switch (this.getterCodeVerificationStatus) {
        case 'verified':
          this.isCodeValid = true
          this.isLoading = false
          this.$router.push({ name: 'completar-registro' })
          break
        case 'registered':
          this.isLoading = false
          this.$router.push({ name: 'landing' })
          break
        case 'error':
          this.isCodeValid = false
          this.isLoading = false
          this.showAlert = true
          break
      }
    },
    reSendCode () {
      this.$router.push({ name: 'ingresar' })
    }
  },
  computed: {
    ...mapGetters('auth', {
      getterCodeVerificationStatus: 'getCodeVerificationStatus'
    })
  },
  components: {
    codeVerificationIcon,
    Alert
  },
  mounted () {
    const oneMinute = 60
    const display = this.$refs.timer
    this.startTimer(oneMinute, display)
  },
  beforeRouteEnter (to, from, next) {
    next(vm => {
      vm.prevLink = from.name
    })
  }
}
</script>
