import axios from 'axios'

const URL = process.env.VUE_APP_URL
const headers = {
  token: process.env.VUE_APP_TOKEN
}

export const generateCodeApi = ({ payload }) =>
  axios.post(`${URL}/api/v1/auth/generate_code`, payload, {
    headers
  })

export const verifyCodeApi = ({ payload }) =>
  axios.post(`${URL}/api/v1/auth/verify_code`, payload, {
    headers
  })

export const completeRegistration = ({ payload, headers }) =>
  axios.post(`${URL}/api/v1/auth/complete_registration`, payload, {
    headers
  })

export const sendUserId = ({ payload, clientId, headers }) =>
  axios.put(`${URL}/api/v1/users/${clientId}`, payload, {
    headers
  })

export const getReferences = ({ headers }) =>
  axios.get(`${URL}/api/v1/references`, {
    headers
  })

export const createReference = ({ headers, payload }) =>
  axios.post(`${URL}/api/v1/references`, payload, {
    headers
  })
