<template>
  <transition name="fade" mode="out-in" appear>
    <div class="personal-data">
      <div class="form__card form__card--large outer-pad">
        <header class="form__card-header">
          <div class="h1">Datos personales</div>
        </header>
        <p class="form__card-description">Para que puedas acceder a los servicios y beneficios de Prospery, es necesario que sepamos más de ti.</p>
        <!-- <form @submit.prevent="this.$parent.stepCount()" action="submit" class="form__card-fields"> -->
        <form @submit.prevent="submitForm()" action="submit" class="form__card-fields">
          <fieldset>
            <div class="silc-grid">
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Nombre</label>
                <input type="text" placeholder="" v-model="personalData.first_name">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Apellidos</label>
                <input type="text" placeholder="" v-model="personalData.last_name">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Fecha de Nacimiento
                  <div class="tooltip">
                    <tool-tip-icon></tool-tip-icon>
                    <span class="tooltiptext">Tooltip text</span>
                  </div>
                </label>
                <input type="date" name="begin" v-model="personalData.birthdate" placeholder="dd-mm-yyyy" min="1960-01-01" max="2002-1-1">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800 silc-grid--relative">
                <label for="" class="label--input">Dirección</label>
                  <div class="tooltip">
                    <tool-tip-icon></tool-tip-icon>
                    <span class="tooltiptext">Tooltip text</span>
                  </div>
                  <autocomplete-list :addressResults="addressData" ref="autocomplete" v-show="personalData.address.street && !addressSelected" @sendAddress="getAddress"></autocomplete-list>
                <input v-on:input="searchAddress" type="address" placeholder="" v-model="personalData.address.street">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Correo electrónico</label>
                <input required type="email" placeholder="" v-model="personalData.email" @blur="validateEmail">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <div class="select">
                <label for="" class="label--input">Estado Laboral</label>
                <select id="job_state" name="country" class="select-standard" v-model="personalData.job_state">
                  <option :value="null" disabled selected>Selecciona una opción</option>
                  <option value="employee">Empleado</option>
                  <option value="freelancer">Independiente</option>
                  <option value="pensioner">Pensionado</option>
                </select>
              </div>
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <div class="select">
                <label for="" class="label--input">Escolaridad</label>
                <select id="scholarship" name="country" class="select-standard" v-model="personalData.scholarship">
                  <option :value="null" disabled selected>Selecciona una opción</option>
                  <option value="primary">Primaria</option>
                  <option value="high_school">Bachillerato</option>
                  <option value="technical">Técnico</option>
                  <option value="technological">Tecnólogo</option>
                  <option value="university">Universitario</option>
                  <option value="postgraduate">Posgrado</option>
                  <option value="nothing">Nuguna</option>
                  <option value="other">Otro</option>
                </select>
              </div>
              </div>
              <div class="silc-grid__col silc-grid__col--6-800 silc-grid--relative">
                <label for="" class="label--input">Contraseña</label>
                <input v-on:input="validatePassword" type="password" placeholder="" v-model="personalData.password">
                <p class="personal-data__password-instruction" v-if="!this.validPassword">La contraseña debe contener al menos 8 carácteres, mayúscula, símbolo y números</p>
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Confirma tu contraseña</label>
                <input v-on:input="validatePasswordCoincidence" type="password" placeholder="" v-model="personalData.passwordConfirmation">
                <p v-if="!this.passwordCoincidence && (this.personalData.password && this.personalData.passwordConfirmation)">La contraseña no coincide</p>
              </div>
            </div>
          </fieldset>
          <button class="button button--large"
            :class="{'button--disabled': !this.allDataFilled}"
            :disabled="!this.allDataFilled"
            >
              <span @click="submitForm">Continuar</span>
          </button>
        </form>
      </div>
      <div class="alert-wrapper">
        <alert v-if="!this.allDataFilled && this.submitted || this.onError" typeOfAlert="allFieldsNeeded" class="personal-data__alert" ></alert>
      </div>
    </div>
  </transition>
</template>

<script>
import { mapActions, mapGetters } from 'vuex'
// @ is an alias to /src
import ToolTipIcon from '../../icons/textfields/tooltipActive'
import Alert from '../Alert.vue'
import AutocompleteList from './AutocompleteList.vue'
import axios from 'axios'
const URL = 'https://prospery-api.herokuapp.com'

export default {
  name: 'PersonalData',
  data () {
    return {
      personalData: {
        first_name: '',
        last_name: '',
        birthdate: '',
        email: '',
        password: '',
        literal_address: 'none',
        job_state: '',
        scholarship: '',
        passwordConfirmation: '',
        address: {
          street: '',
          city: '',
          country: 'COLOMBIA',
          country_code: 'CO',
          description: '',
          latitude: '',
          longitude: '',
          zipcode: ''
        }
      },
      addressData: [],
      fieldsErrors: [],
      passwordCoincidence: false,
      submitted: false,
      onError: false,
      validEmail: false,
      validPassword: false
    }
  },
  methods: {
    ...mapActions('auth', {
      actionSavePersonalInformation: 'savePersonalDataForm'
    }),
    submitForm () {
      if (this.allDataFilled && this.validEmail) {
        this.actionSavePersonalInformation({ ...this.personalData })
        this.$parent.stepCount()
      }
    },
    getAddress (element) {
      this.personalData.address.street = element.address
    },
    validatePasswordCoincidence (e) {
      const { value } = e.target
      this.passwordCoincidence = value === this.personalData?.password && this.personalData?.passwordConfirmation !== ''
    },
    validatePassword (e) {
      const { value } = e.target
      if (/^(?=.*[0-9])(?=.*[- ?!@#$%^&*\\/\\])(?=.*[A-Z])(?=.*[a-z])[a-zA-Z0-9- ?!@#$%^&*\\/\\]{8,30}$/.test(value)) {
        this.validPassword = true
      } else {
        this.validPassword = false
      }
      this.passwordCoincidence = this.personalData?.password === this.personalData?.passwordConfirmation
    },
    validateEmail () {
      if (/^\w+([\\.-]?\w+)*@\w+([\\.-]?\w+)*(\.\w{2,3})+$/.test(this.personalData.email)) {
        this.validEmail = true
      } else {
        this.validEmail = false
      }
    },
    async searchAddress (e) {
      const { value } = e.target
      const headers = {
        'access-token': localStorage.getItem('accessToken') || '',
        expiry: localStorage.getItem('expiry') || '',
        'token-type': localStorage.getItem('tokenType') || '',
        uid: localStorage.getItem('uid') || '',
        client: localStorage.getItem('client') || ''
      }

      if (value.length > 0) {
        const response = await axios
          .get(`${URL}/api/v1/addresses/search?limit=5&address=${encodeURI(value)}&region=CO`, {
            headers
          })
          .catch(() => {
          })

        this.addressData = response.data.map(add => ({
          id: add.id,
          address: add.structured_formatting.main_text,
          location: add.structured_formatting.secondary_text,
          description: add.id
        }))
      }
    },
    async getAddressDetail (id) {
      const headers = {
        'access-token': localStorage.getItem('accessToken') || '',
        expiry: localStorage.getItem('expiry') || '',
        'token-type': localStorage.getItem('tokenType') || '',
        uid: localStorage.getItem('uid') || '',
        client: localStorage.getItem('client') || ''
      }
      const response = await axios
        .get(`${URL}/api/v1/addresses/place/${id}`, {
          headers
        })
        .catch(() => {
        })

      if (response.data) {
        const addressDetail = {
          city: response.data.address_components.find(dir => dir.types.includes('locality', 'political', 'administrative_area_level_1'))?.long_name || 'none',
          description: response.data.url,
          latitude: response.data.geometry.location.lat,
          longitude: response.data.geometry.location.lng,
          zipcode: response.data.address_components.find(dir => dir.types.includes('postal_code'))?.long_name || 'none'
        }

        this.personalData.address.city = addressDetail.city
        this.personalData.address.description = addressDetail.description
        this.personalData.address.latitude = addressDetail.latitude
        this.personalData.address.longitude = addressDetail.longitude
        this.personalData.address.zipcode = addressDetail.zipcode
      }
    }
  },
  components: {
    ToolTipIcon,
    Alert,
    AutocompleteList
  },
  mounted () {
  },
  computed: {
    ...mapGetters('auth', {
      getterCompleteData: 'getCompletePersonalDataStatus'
    }),
    allDataFilled () {
      return Object.values(this.personalData).every(x => (x !== '')) && Object.values(this.personalData.address).every(x => (x !== '')) && this.validPassword && this.passwordCoincidence
    },
    addressSelected () {
      const addressId = this.$refs.autocomplete.storedAddress.id
      if (addressId) {
        this.getAddressDetail(addressId)
      }
      return this.personalData.address.street === this.$refs.autocomplete.storedAddress.address
    }
  }
}
</script>
