import { createRouter, createWebHashHistory } from 'vue-router'
/// home views and components
import Landing from '../views/home/Landing.vue'
import CreditDetail from '../views/home/CreditDetail.vue'

/// login views and components
import Login from '../views/Login.vue'
import SignUp from '../components/signup/SignUp.vue'
import SignIn from '../components/signin/SignIn.vue'
import RecoverAccount from '../components/signin/RecoverAccount.vue'
import CreateNewPass from '../components/signin/CreateNewPass.vue'
import CodeVerification from '../components/signin/CodeVerification.vue'
import CompleteUserData from '../components/signup/CompleteUserData.vue'

/// account views and components
import MyAccount from '../views/account/MyAccount.vue'
import AccountPersonalReferences from '../views/account/AccountPersonalReferences'
import AddAccountReference from '../views/account/AddAccountReference'
import AddAccountExperience from '../views/account/AddAccountExperience'
import WorkExperience from '../views/account/WorkExperience'
import PersonalData from '../views/account/AccountPersonalData.vue'
import FinancialData from '../views/account/FinancialData.vue'
import myAccountElements from '../components/account/myAccountElements'

/// dashboard views and components
import Dashboard from '../views/Dashboard.vue'
import Loans from '../views/loans/Loans.vue'
import LoanDetails from '../views/loans/LoanDetails.vue'
import PayLoan from '../views/loans/PayLoan.vue'
import ManualPay from '../views/loans/ManualPay.vue'
import AskLoan from '../views/loans/AskLoan.vue'
import prestamosList from '../components/dashboard/loans/prestamosList.vue'
import loanDetailsElements from '../components/dashboard/loans/loanDetailsElements.vue'
import store from '../store'

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Dashboard,
    meta: { requiresAuth: false },
    redirect: {
      name: 'landing'
    },
    children: [
      {
        path: '',
        name: 'landing',
        component: Landing
      },
      {
        path: 'detalle-credito',
        name: 'detalle-credito',
        component: CreditDetail
      },
      {
        path: 'mis-prestamos',
        name: 'prestamos',
        component: Loans,
        children: [
          {
            path: '',
            name: 'mis-prestamos',
            component: prestamosList
          },
          {
            path: 'detalles-de-prestamo/:id',
            name: 'detalles',
            component: LoanDetails,
            props: (route) => ({
              ...route.params
            }),
            children: [
              {
                path: '',
                name: 'detalles-de-prestamo',
                component: loanDetailsElements
              },
              {
                path: 'pagar-cuota',
                name: 'pagar-cuota',
                component: PayLoan
              },
              {
                path: 'pago-manual',
                name: 'pago-manual',
                component: ManualPay
              }
            ]
          },
          {
            path: 'solicitar-prestamo',
            name: 'solicitar-prestamo',
            component: AskLoan
          }
        ]
      },
      {
        path: 'mi-cuenta',
        name: 'cuenta',
        component: MyAccount,
        children: [
          {
            path: '',
            name: 'mi-cuenta',
            component: myAccountElements
          },
          {
            path: 'datos-personales',
            name: 'datos-personales',
            component: PersonalData
          },
          {
            path: 'referencias-personales',
            name: 'referencias-personales',
            component: AccountPersonalReferences
          },
          {
            path: 'agregar-referencia',
            name: 'agregar-referencia',
            component: AddAccountReference
          },
          {
            path: 'experiencia-laboral',
            name: 'experiencia-laboral',
            component: WorkExperience
          },
          {
            path: 'agregar-experiencia',
            name: 'agregar-experiencia',
            component: AddAccountExperience
          },
          {
            path: 'datos-financieros',
            name: 'datos-financieros',
            component: FinancialData
          }
        ]
      }
    ]
  },
  {
    path: '/login',
    name: 'Login',
    component: Login,
    redirect: {
      name: 'SignIn'
    },
    children: [
      {
        path: 'registro',
        name: 'registro',
        component: SignUp,
        children: [
          {
            path: 'completar-registro',
            name: 'completar-registro',
            component: CompleteUserData,
            meta: { requiresAuth: false }
          }
        ]
      },
      {
        path: 'ingresar',
        name: 'ingresar',
        component: SignIn,
        meta: { requiresVisitor: false }
      },
      {
        path: 'recuperar-cuenta',
        name: 'recuperar-cuenta',
        component: RecoverAccount
      },
      {
        path: 'create-new-pass',
        name: 'createnewpass',
        component: CreateNewPass
      },
      {
        path: 'code-verification',
        name: 'codeverification',
        component: CodeVerification,
        meta: { requiresVisitor: true }
      }
    ]
  }
]

const router = createRouter({
  routes,
  history: createWebHashHistory()
})

router.beforeEach((to, from, next) => {
  if (to.matched.some(route => route.meta.requiresAuth)) {
    if (!store.state.auth.AuthData.accessToken) {
      next({
        name: 'ingresar'
      })
    } else if (to.name !== 'completar-registro' && store.state.auth.AuthData.accessToken && store.state.auth.registrationStatus === 'in-progress') {
      next({
        name: 'completar-registro'
      })
    } else {
      next()
    }
  } else if (to.matched.some(route => route.meta.requiresVisitor)) {
    if (store.state.auth.AuthData.accessToken && store.state.auth.AuthData.expiry && store.state.auth.AuthData.tokenType && store.state.auth.AuthData.uid && store.state.auth.AuthData.client) {
      next({
        name: 'Home'
      })
    } else {
      next()
    }
  } else {
    next()
  }
})

export default router
