<template>
  <transition name="fade" mode="out-in" appear>
    <div class="form__card form__card--large outer-pad">
      <div class="add-selfie__wrapper outer-pad">
        <div class="silc-grid">
          <div class="silc-grid__col silc-grid__col--5-600">
            <div class="h1 add-selfie__title add-selfie__title--mobile">Ahora debes adjuntar una foto de perfil</div>
            <div class="add-selfie__image"></div>
          </div>
          <div class="silc-grid__col silc-grid__col--7-600">
            <div class="add-selfie__description">
              <div class="h1 add-selfie__title">Ahora debes adjuntar una foto de perfil</div>
              <p>Con la foto de tu cara compararemos tu identidad con tu documento. Si no eres tú, tu cuenta de Prospery será bloqueada.</p>
              <p>La foto debe ser tomada en un sitio con buena iluminación, solo tu cara (sin gafas) y a la altura de tu cara.</p>
            </div>
            <div @click.prevent="takeSelfie = true" class="add__selfie-button__wrapper">
              <div class="add__selfie-instructions">
                <profile-photo-icon></profile-photo-icon>
                <div class="add__id-instructions__inner-wrapper">
                  <p>Sigue las instrucciones anteriores y toma tu foto de perfil</p>
                  <button
                    v-if="!photo.idPic"
                    class="button button--small"
                    @click.prevent="openPhoto('front')"
                  >Tomar foto</button>
                  <button
                    class="button button--small"
                    v-else
                    @click.prevent="openPhoto('front')"
                  >Tomar otra foto</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <footer class="add__id-footer">
        <div class="id-footer__instructions">
          <security-icon></security-icon>
          <p class="paragraph--dark">No compartimos documento de identificación con ningún otro usuario de Prospery.</p>
        </div>
        <button
              :disabled="!photo.idPic"
              :class="{'button--disabled': !photo.idPic}"
              type="button"
              class="button"
              @click="this.verifyCustomer()">
              Continuar
            </button>
      </footer>
      <take-selfie
        @close="closeCamera"
        @sendPhoto="sendPhoto"
        v-if="takeSelfie"
      ></take-selfie>
    </div>
  </transition>
</template>

<script>
import profilePhotoIcon from '../../icons/signup/profilePhotoIcon'
import securityIcon from '../../icons/general/securityIcon'
import TakeSelfie from './TakeSelfie'
import { mapActions } from 'vuex'

export default {
  data () {
    return {
      takeSelfie: false,
      photo: {
        idPic: ''
      }
    }
  },
  components: {
    profilePhotoIcon,
    securityIcon,
    TakeSelfie
  },
  methods: {
    ...mapActions('auth', {
      verificationCustomer: 'verificationCustomer'
    }),
    closeCamera () {
      this.takeSelfie = false
    },
    sendPhoto (value) {
      this.photo.idPic = value
    },
    async verifyCustomer () {
      this.submitted = true
      const userInfo = {
        user: {
          id_front_photo: this.idPhotos.idFront,
          id_back_photo: this.idPhotos.idBack,
          verification_photo: this.photo.idPic
        }
      }
      await this.verificationCustomer({
        ...userInfo
      })
      if (this.getterCompleteData?.status === 'success') {
        console.log('success')
        this.loading = false
        this.$parent.stepCount()
      }
      if (this.getterCompleteData?.status === 'error') {
        this.onError = true
        this.loading = false
        this.fieldsErrors = this.getterCompleteData.errors
      }
    }
  },
  computed: {
    idPhotos () {
      console.log(this.$store.state.auth.idPhotos)
      return this.$store.state.auth.idPhotos
    }
  }
}
</script>
