<template>
  <div class="complete-user-data__container">
    <h1 class="sign-up__title">Completa tu Registro
      <span class="line">
        <span class="line__progress" :style="{transform: `scaleX(${1 / (componentsLength + 1) * step})`}"></span>
        <span class="line__dot" v-for="(step) of componentsLength" :key="step" :class="{'line__dot--active' : isDotActive(step)}"></span>
      </span>
    </h1>
    <personal-data v-if="step === 1"></personal-data>
    <upload-i-d v-if="step === 2"></upload-i-d>
    <add-i-d v-if="step === 3"></add-i-d>
    <add-selfie v-if="step === 4"></add-selfie>
    <done-status v-if="step === 5"></done-status>
  </div>
</template>

<script>
import PersonalData from './PersonalData'
import UploadID from './UploadID.vue'
import AddID from './AddID.vue'
import AddSelfie from './AddSelfie.vue'
import doneStatus from '../../animations/doneStatus'

export default {
  name: 'CompleteUserData',
  data () {
    return {
      step: 1,
      isLoading: false,
      componentsLength: Object.keys(this.$options.components).length
    }
  },
  components: {
    PersonalData, UploadID, AddID, AddSelfie, doneStatus
  },
  methods: {
    stepCount () {
      this.isLoading = true
      setTimeout(() => {
        this.isLoading = false
        this.step++
      })
    },
    backToStepOne () {
      this.step = 1
    },
    isDotActive (index) {
      console.log(index)
      return index <= this.step
    }
  }
}
</script>
