<template>
  <transition name="fade" mode="out-in" appear>
    <div class="add-id">
      <div class="form__card form__card--large outer-pad">
        <header class="form__card-header">
          <div class="h1">Selecciona el tipo de documento</div>
        </header>
        <form @submit.prevent="this.$parent.stepCount()" action="submit" class="form">
          <div class="silc-grid">
            <div class="silc-grid__col silc-grid__col--6-800">
              <div class="select">
                <label for="" class="label--input">País o región de expedición</label>
                <select class="select-standard" v-model="idData.country">
                  <option value="Colombia" selected>Colombia</option>
                  <option value="Peru">Perú</option>
                  <option value="Chile">Chile</option>
                  <option value="Argentina">Argentina</option>
                </select>
              </div>
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <div class="select">
                <label for="" class="label--input">Tipo de documento</label>
                <select id="country" name="country" class="select-standard" v-model="idData.documentType">
                  <option :value="null" disabled selected>Selecciona una opción</option>
                  <option value="IN">Cédula de Ciudadanía</option>
                  <option value="IN">Cédula de Extranjero</option>
                  <option value="IN">Tarjeta de Identidad</option>
                </select>
              </div>
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <label for="" class="label--input">Número de documento</label>
              <div class="tooltip">
                <tool-tip-icon></tool-tip-icon>
                <span class="tooltiptext">Tooltip text</span>
              </div>
              <input v-model="idData.idNumber" type="text">
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <label for="" class="label--input">Fecha de expedición</label>
              <div class="tooltip">
                <tool-tip-icon></tool-tip-icon>
                <span class="tooltiptext">Tooltip text</span>
              </div>
              <input v-model="idData.releaseDate" type="date" placeholder="dd-mm-yyyy" min="1960-01-01" max="2002-1-1">
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <label for="" class="label--input">Foto del lado frontal de tu documento</label>
              <div class="tooltip">
                <tool-tip-icon></tool-tip-icon>
                <span class="tooltiptext">Tooltip text</span>
              </div>
              <div class="add__id-button__wrapper">
                <id-front-icon></id-front-icon>
                <div class="add__id-instructions">
                  <p>El archivo debe ser en .png o .jpg, y debe pesar menos de 5mb.</p>
                  <button
                    class="button button--small"
                    @click.prevent="openPhoto('frontPicSrc')"
                  >Tomar foto</button>
                </div>
              </div>
            </div>
            <div class="silc-grid__col silc-grid__col--6-800">
              <label for="" class="label--input">Foto del lado posterior de tu documento</label>
              <div class="tooltip">
                <tool-tip-icon></tool-tip-icon>
                <span class="tooltiptext">Tooltip text</span>
              </div>
              <div class="add__id-button__wrapper">
                <id-back-icon></id-back-icon>
                <div class="add__id-instructions">
                  <p>El archivo debe ser en .png o .jpg, y debe pesar menos de 5mb.</p>
                  <button
                    class="button button--small"
                    @click.prevent="openPhoto('backPicSrc')"
                  >Tomar foto</button>
                </div>
              </div>
            </div>
          </div>
          <footer class="add__id-footer">
            <div class="id-footer__instructions">
              <security-icon></security-icon>
              <p class="paragraph--dark">No compartimos documento de identificación con ningún otro usuario de Prospery.</p>
            </div>
            <button
              :disabled="!this.allDataFilled"
              :class="{'button--disabled': !this.allDataFilled}"
              type="button"
              class="button"
              v-if="!this.loading"
              @click="this.submitForm()">
              Continuar
            </button>
            <p style="text-align:center" v-if="loading">Loading...</p>
          </footer>
        </form>
        <p v-if="onError && fieldsErrors.length > 0" style="text-align:center">Errores</p>
        <ul v-if="onError && fieldsErrors.length > 0" style="text-align:center" id="example-1">
          <li v-for="item in fieldsErrors" :key="item.index">
            - {{ item }}
          </li>
        </ul>
      </div>
      <div class="alert-wrapper">
         <alert v-if="this.onError" typeOfAlert="allFieldsNeeded" class="personal-data__alert" ></alert>
        </div>
      <transition name="fade" mode="out-in">
        <take-photo
          v-if="takePhoto"
          :cameraType="cameraType"
          @sendPhoto="sendPhoto"
          @close="closeCamera" ></take-photo>
      </transition>
    </div>
  </transition>
</template>

<script>
import toolTipIcon from '../../icons/textfields/tooltipActive'
import idFrontIcon from '../../icons/signup/idFrontIcon'
import idBackIcon from '../../icons/signup/idBackIcon'
import securityIcon from '../../icons/general/securityIcon'
import TakePhoto from './TakePhoto.vue'
import Alert from '../Alert.vue'
import { mapActions, mapGetters } from 'vuex'

export default {
  data () {
    return {
      frontIDimg: null,
      takePhoto: false,
      takePhotoFront: false,
      cameraType: '',
      submitted: '',
      loading: false,
      onError: false,
      fieldsErrors: [],
      idData: {
        country: 'Colombia',
        documentType: null,
        idNumber: '',
        releaseDate: '',
        frontPicSrc: '',
        backPicSrc: ''
      }
    }
  },
  components: {
    toolTipIcon,
    idFrontIcon,
    idBackIcon,
    securityIcon,
    TakePhoto,
    Alert
  },
  methods: {
    ...mapActions('auth', {
      actionCompleteProfile: 'completePersonalData',
      savePhotos: 'savePhotos'
    }),
    async submitForm () {
      if (this.allDataFilled) {
        this.loading = true
        this.submitted = true
        const userInfo = {
          ...this.getterCompleteData.personalData,
          identification_type: this.idData.documentType,
          identification: this.idData.idNumber,
          expedition_date: this.idData.releaseDate
        }
        await this.actionCompleteProfile({
          ...userInfo
        })
      }
      if (this.getterCompleteData?.status === 'success') {
        console.log('success')
        this.loading = false
        this.$parent.stepCount()
      }
      if (this.getterCompleteData?.status === 'error') {
        this.onError = true
        this.loading = false
        this.fieldsErrors = this.getterCompleteData.errors
      }
    },
    openPhoto (cameraType) {
      this.cameraType = cameraType
      this.takePhoto = true
    },
    closeCamera () {
      this.takePhoto = false
      const data = {
        idFront: this.idData.frontPicSrc,
        idBack: this.idData.backPicSrc
      }
      this.savePhotos(data)
    },
    handleFileChange (evt, type) {
      this.idData[type] = evt.target
    },
    sendPhoto ({ photo, type }) {
      this.idData[type] = photo
    },
    savePhoto () {
      this.$emit('sendPhoto', this.idData)
    }
  },
  computed: {
    ...mapGetters('auth', {
      getterCompleteData: 'getCompletePersonalDataStatus'
    }),
    allDataFilled () {
      return Object.values(this.idData).every(x => (x !== ''))
    }
  }
}
</script>
